#include <bits/stdc++.h>
using namespace std;

int main() {
    string s1, s2;

    // Read two input strings
    cin >> s1;
    cin >> s2;

    int good = 0;  // Variable to track the difference between characters
    vector<int> a;  // Vector to store ASCII values of characters from s1

    // Convert characters of s1 into their ASCII values and store them in vector 'a'
    for(auto i : s1) {
        a.push_back((int)i);
    }

    // Sort the vector 'a' to prepare for binary search
    sort(a.begin(), a.end());

    int res = 0;  // Variable to store the final result, i.e., total "good" values
    int prev = (int)s1[0];  // Store the ASCII value of the first character of s1 as the initial 'previous' value

    // Loop through each character of string s2
    for(auto i : s2) {
        int b = (int)i;  // Convert character 'i' from s2 to its ASCII value 'b'

        int l = 0, r = a.size() - 1;  // Initialize the binary search boundaries
        int good = INT_MAX;  // Initialize 'good' to a large value to find the minimum difference
        int curr = -1;  // Initialize 'curr' to track the closest character from s1

        // Binary search for the closest character to 'b' in the sorted vector 'a'
        while(l <= r) {
            int mid = (l + r) / 2;  // Find the middle index

            if(a[mid] == b) {  // If an exact match is found
                curr = prev;  // Update curr to the value of 'prev'
                good = 0;  // No difference if the characters match exactly
                break;  // Exit the loop as we found an exact match
            }
            else if(a[mid] < b) {  // If the middle element is less than 'b'
                // Check if the difference between 'a[mid]' and 'b' is smaller than the current 'good'
                if(abs(a[mid] - b) < good) {
                    good = abs(a[mid] - b);  // Update 'good' with the smaller difference
                    curr = a[mid];  // Update 'curr' with the current closest value
                }
                // If the difference is equal but 'a[mid]' is closer to 'prev', update 'curr' and 'good'
                else if(abs(a[mid] - b) == good) {
                    if(abs(curr - prev) > abs(a[mid] - prev)) {
                        curr = a[mid];  // Update 'curr' to the closer value
                        good = abs(a[mid] - prev);  // Update 'good' to the closer value
                    }
                    else {
                        good = abs(curr - prev);  // Keep 'good' unchanged if the current closest is better
                    }
                }
                l = mid + 1;  // Move to the right half of the array
            }
            else {  // If the middle element is greater than 'b'
                // Same logic as above but in reverse, as we now check the left side of the array
                if(abs(a[mid] - b) < good) {
                    good = abs(a[mid] - b);
                    curr = a[mid];
                }
                else if(abs(a[mid] - b) == good) {
                    if(abs(curr - prev) > abs(a[mid] - prev)) {
                        curr = a[mid];
                        good = abs(a[mid] - prev);
                    }
                    else {
                        good = abs(curr - prev);
                    }
                }
                r = mid - 1;  // Move to the left half of the array
            }
        }

        prev = curr;  // Update 'prev' to the closest character found in this iteration
        res += good;  // Add the "good" value (difference) to the result
    }

    // Output the total sum of "good" values
    cout << res;
}

