    // Read the two input strings s1 and s2
    const s1 = input[0];
    const s2 = input[1];

    // Convert characters of s1 to their ASCII values and store them in an array
    const a = [];
    for (let i = 0; i < s1.length; i++) {
        a.push(s1.charCodeAt(i));  // Convert each character to its ASCII value
    }

    // Sort the array of ASCII values
    a.sort((x, y) => x - y); // Sort in ascending order

    let res = 0;  // To store the result
    let prev = s1.charCodeAt(0);  // Initialize previous character's ASCII value

